// n8n Function node code
// Input: items (each item.json is a row from Google Sheets / other source)
// Output: single item: { json: { lastDate: "YYYY-MM-DD" } }

const rows = items; // n8n provides 'items' automatically

function excelSerialToDate(serial) {
  // Excel/Google serial => JS Date (UTC)
  // Excel incorrectly treats 1900 as leap year; most simple conversion:
  const epoch = Date.UTC(1899, 11, 30); // 1899-12-30
  return new Date(epoch + Math.round(serial) * 86400000);
}

function tryParseDate(v) {
  if (v === null || v === undefined || v === '') return null;

  // if it's already a Date
  if (Object.prototype.toString.call(v) === '[object Date]' && !isNaN(v)) return v;

  // if it's a number (possible Excel serial)
  if (typeof v === 'number' && isFinite(v)) {
    return excelSerialToDate(v);
  }

  // strings: normalize
  let s = String(v).trim();

  // remove surrounding quotes/commas
  s = s.replace(/^["']|["']$/g, '');

  // common patterns:
  // 1) ISO-ish "YYYY-MM-DD" or "YYYY-MM-DDTHH:MM:SS" or "YYYY-MM-DD HH:MM"
  // 2) "YYYY/MM/DD"
  // 3) "DD/MM/YYYY" (try as fallback if the first parses invalid)
  // 4) "MM/DD/YYYY"
  // Try to extract numeric tokens
  // First try YYYY-MM-DD or YYYY/MM/DD
  const isoMatch = s.match(/^(\d{4})[-\/](\d{1,2})[-\/](\d{1,2})/);
  if (isoMatch) {
    const yyyy = parseInt(isoMatch[1], 10);
    const mm = parseInt(isoMatch[2], 10);
    const dd = parseInt(isoMatch[3], 10);
    // construct as UTC date to avoid local timezone shift
    return new Date(Date.UTC(yyyy, mm - 1, dd));
  }

  // Try numbers separated by non-digits (could be DD/MM/YYYY or MM/DD/YYYY)
  const tokens = s.split(/\D+/).filter(Boolean);
  if (tokens.length >= 3) {
    // guess: if first token has 4 digits -> it's year-first already handled, else try dd/mm/yyyy
    if (tokens[0].length === 4) {
      const y = parseInt(tokens[0], 10);
      const m = parseInt(tokens[1], 10);
      const d = parseInt(tokens[2], 10);
      return new Date(Date.UTC(y, m - 1, d));
    } else {
      // try both interpretations: prefer day-first (DD/MM/YYYY) unless month > 12
      const a = parseInt(tokens[0], 10);
      const b = parseInt(tokens[1], 10);
      const c = parseInt(tokens[2], 10);
      // if b > 12 then it's definitely day-first (a=day)
      if (b > 12) {
        return new Date(Date.UTC(c, a - 1, b)); // but this is unusual; still try
      }
      // assume DD/MM/YYYY
      if (c > 31) {
        // maybe MM/DD/YY etc. fallback to JS Date.parse
        const parsed = Date.parse(s);
        if (!isNaN(parsed)) return new Date(parsed);
        return null;
      }
      // assume dd/mm/yyyy
      return new Date(Date.UTC(c, b - 1, a));
    }
  }

  // As final fallback, try Date.parse (may handle "Dec 1 2025" etc.)
  const parsed = Date.parse(s);
  if (!isNaN(parsed)) return new Date(parsed);

  return null;
}

// Find the column key that contains visit start date (case-insensitive)
function findDateKey(jsonRow) {
  const keys = Object.keys(jsonRow || {});
  // first, exact-ish match:
  for (const k of keys) {
    if (/^\s*visit\s*start\s*date\s*$/i.test(k)) return k;
  }
  // second, fuzzy match
  for (const k of keys) {
    if (/visit.*start.*date/i.test(k)) return k;
  }
  // third, any header that contains "date" (fallback)
  for (const k of keys) {
    if (/date/i.test(k) && /visit|start|begin/i.test(k)) return k;
  }
  // last fallback: any key containing just "date"
  for (const k of keys) {
    if (/date/i.test(k)) return k;
  }
  return null;
}

let maxTs = -Infinity;
let maxDate = null;
let detectedKey = null;

// If there are many rows, it's fine — iterate
for (const row of rows) {
  const json = row.json || {};
  // on first iteration, detect the key
  if (!detectedKey) detectedKey = findDateKey(json);

  if (!detectedKey) continue; // can't find a date column in this row

  const raw = json[detectedKey];
  const d = tryParseDate(raw);

  if (d && !isNaN(d.getTime())) {
    const ts = d.getTime();
    if (ts > maxTs) {
      maxTs = ts;
      maxDate = d;
    }
  }
}

// Prepare output
if (!maxDate) {
  // no valid date found
  return [{ json: { lastDate: null, message: 'No valid dates found in column.' } }];
}

// output ISO date string YYYY-MM-DD
const outIsoDate = maxDate.toISOString().slice(0, 10);

return [{ json: { lastDate: outIsoDate } }];
